class Solution:
    def __init__(self):
        self.heap = []

    def solve(self):
        for line in sys.stdin:
            if line == '0
': break
            line = line.strip().split(' ')
            if line[0] == '1': self.add(line[1])
            if line[0] == '2': self.erase()

    def add(self, x):
        self.heap.append(int(x))
        self.heapifyUp()

    def erase(self):
        if self.heap:
            self.heap.remove(max(self.heap))
            self.heapifyDown()

    def heapifyUp(self):
        current = len(self.heap) - 1
        while current != 0:
            parent = (current - 1) // 2
            if self.heap[parent] > self.heap[current]:
                swap = self.heap[parent], self.heap[current]
                self.heap[parent], self.heap[current] = swap
                current = parent
            else:
                break

    def heapifyDown(self):
        current = 0
        while True:
            leftChild = 2 * current + 1
            rightChild = 2 * current + 2
            largest = current
            if leftChild < len(self.heap) and self.heap[leftChild] > self.heap[largest]:
                largest = leftChild
            if rightChild < len(self.heap) and self.heap[rightChild] > self.heap[largest]:
                largest = rightChild
            if largest == current:
                break
            swap = self.heap[largest], self.heap[current]
            self.heap[largest], self.heap[current] = swap
            current = largest

    def swap(self, a, b):
        swap = a, b
        return swap

import sys
if __name__ == '__main__':
    solution = Solution()
    solution.solve()
    for x in solution.heap:
        print(x, end=' ')
    print('')

